select v_1 as "n_name", v_2 as "revenue" from (select v_3 as v_1, sum(v_4 * (cast('1' as integer) - v_5)) as v_2 from (select * from (select * from (select * from (select * from (select * from (select "c_custkey" as v_6, "c_name" as v_7, "c_address" as v_8, "c_nationkey" as v_9, "c_phone" as v_10, "c_acctbal" as v_11, "c_mktsegment" as v_12, "c_comment" as v_13 from "customer") l inner join (select * from (select "o_orderkey" as v_14, "o_custkey" as v_15, "o_orderstatus" as v_16, "o_totalprice" as v_17, "o_orderdate" as v_18, "o_orderpriority" as v_19, "o_clerk" as v_20, "o_shippriority" as v_21, "o_comment" as v_22 from "orders") s where (v_18 >= (date('1994-01-01', '+0 seconds'))) and (v_18 < (date('1994-01-01', '+1 year')))) r on v_6 = v_15) l inner join (select "l_orderkey" as v_23, "l_partkey" as v_24, "l_suppkey" as v_25, "l_linenumber" as v_26, "l_quantity" as v_27, "l_extendedprice" as v_4, "l_discount" as v_5, "l_tax" as v_28, "l_returnflag" as v_29, "l_linestatus" as v_30, "l_shipdate" as v_31, "l_commitdate" as v_32, "l_receiptdate" as v_33, "l_shipinstruct" as v_34, "l_shipmode" as v_35, "l_comment" as v_36 from "lineitem") r on v_23 = v_14) l inner join (select "s_suppkey" as v_37, "s_name" as v_38, "s_address" as v_39, "s_nationkey" as v_40, "s_phone" as v_41, "s_acctbal" as v_42, "s_comment" as v_43 from "supplier") r on v_25 = v_37) l inner join (select "n_nationkey" as v_44, "n_name" as v_3, "n_regionkey" as v_45, "n_comment" as v_46 from "nation") r on v_40 = v_44) l inner join (select * from (select "r_regionkey" as v_47, "r_name" as v_48, "r_comment" as v_49 from "region") s where v_48 = 'ASIA') r on v_45 = v_47) s group by 1) s order by v_2 desc
